const DATACANDY_BASE = process.env.DATACANDY_API_URL!;
const DATACANDY_API_KEY = process.env.DATACANDY_API_KEY!;
const DATACANDY_LOCATION_ID = process.env.DATACANDY_LOCATION_ID!;

class DataCandyClient {
  private async request<T>(
    endpoint: string,
    options: RequestInit = {}
  ): Promise<DataCandyResponse<T>> {
    const response = await fetch(`${DATACANDY_BASE}${endpoint}`, {
      ...options,
      headers: {
        'Authorization': `Bearer ${DATACANDY_API_KEY}`,
        'X-Location-Id': DATACANDY_LOCATION_ID,
        'Content-Type': 'application/json',
        ...options.headers,
      },
    });

    if (!response.ok) {
      throw new DataCandyError(
        `DataCandy API error: ${response.status}`,
        response.status,
        await response.json()
      );
    }

    return response.json();

