// ✅ FIXED
async function generateMagicLink(email) {
  const token = crypto.randomBytes(32).toString('hex');
  const expires = new Date(Date.now() + 15 * 60 * 1000);

  try {
    await db.tokens.create({ token, email, expires });
  } catch (err) {
    // ❌ If this throws, stop here — don't send email
    throw new Error(`Token storage failed: ${err.message}`);
  }

  await sendMagicLinkEmail(email, token); // Only runs if DB succeeded
}
